import{_ as t,c as a,o as s,aj as r}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Choosing Your Data Model","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/choosing-your-data-model.md","filePath":"getting-started/choosing-your-data-model.md"}'),o={name:"getting-started/choosing-your-data-model.md"};function n(i,e,d,l,c,h){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="choosing-your-data-model" tabindex="-1">Choosing Your Data Model <a class="header-anchor" href="#choosing-your-data-model" aria-label="Permalink to “Choosing Your Data Model”">​</a></h1><p>Primitive offers two storage systems — <strong>Documents</strong> and <strong>Databases</strong> — each designed for different use cases. Many apps use both — documents for personal/collaborative data, databases for app-wide shared data. This guide helps you decide which to use where.</p><h2 id="at-a-glance" tabindex="-1">At a Glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to “At a Glance”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Documents</th><th>Databases</th></tr></thead><tbody><tr><td><strong>Where data lives</strong></td><td>Local-first, on the device</td><td>Server-side</td></tr><tr><td><strong>Connectivity</strong></td><td>Offline access, instant local reads</td><td>Requires network connectivity</td></tr><tr><td><strong>Collaboration</strong></td><td>Real-time concurrent editing with conflict-free merging</td><td>Live change feeds via registered subscriptions</td></tr><tr><td><strong>Access model</strong></td><td>All-or-nothing sharing per document</td><td>Per-operation CEL access rules</td></tr><tr><td><strong>Schema</strong></td><td>Schemaless document structures</td><td>Schemaless — save any JSON records</td></tr><tr><td><strong>Size limit</strong></td><td>~10 MB per document</td><td>~5 GB per instance</td></tr><tr><td><strong>Server logic</strong></td><td>N/A</td><td>Server-enforced triggers and computed fields</td></tr></tbody></table><p><strong>Use documents</strong> when users need offline access, real-time collaboration, or all users with access see the same data. <strong>Use databases</strong> when different users need different views of the data, you need server-enforced rules, or datasets are large.</p><h2 id="when-to-use-documents" tabindex="-1">When to Use Documents <a class="header-anchor" href="#when-to-use-documents" aria-label="Permalink to “When to Use Documents”">​</a></h2><p>Documents are local-first collaborative containers. Data lives on the device, syncs automatically, and works offline. Choose documents when:</p><ul><li><strong>Users own the data</strong> — Tasks, notes, projects, personal records</li><li><strong>Real-time collaboration matters</strong> — Multiple users editing shared data simultaneously with conflict-free merging</li><li><strong>Offline access is important</strong> — Users need to work without a network connection</li><li><strong>Data is naturally partitioned by sharing context</strong> — Different people have access to different data sets</li></ul><p>Documents are the right choice for the &quot;inner&quot; data of most productivity and collaboration apps. An individual document works best under ~10 MB — for larger data sets, partition across multiple documents.</p><h2 id="when-to-use-databases" tabindex="-1">When to Use Databases <a class="header-anchor" href="#when-to-use-databases" aria-label="Permalink to “When to Use Databases”">​</a></h2><p>Databases are server-side structured storage with registered operations and expression-based access control. Individual databases hold up to ~5 GB each. Choose databases when:</p><ul><li><strong>Server-enforced rules are required</strong> — Validation, computed fields, or business logic that must run server-side</li><li><strong>Data is shared across all users</strong> — Product catalogs, configuration, lookup tables, shared settings</li><li><strong>You need cross-user queries</strong> — Leaderboards, directories, marketplace listings, aggregated reports</li><li><strong>Access control needs to be per-operation</strong> — Different users can read vs. write, or can only modify their own records</li><li><strong>Admin manages the content</strong> — Content that&#39;s curated centrally, not user-generated</li></ul><div class="tip custom-block"><p class="custom-block-title">Partitioning Databases for Scale</p><p>A single global database works well when your data will stay under ~5 GB. But if there are natural ways to partition your data — by user, organization, team, or other context — and most queries stay within a single partition, consider creating separate databases from the start. This gives you scaling benefits for free and avoids a costly migration later. For example, an app where each organization has its own project data can use a database per organization rather than one large shared database.</p></div><h2 id="using-both-together" tabindex="-1">Using Both Together <a class="header-anchor" href="#using-both-together" aria-label="Permalink to “Using Both Together”">​</a></h2><p>Most non-trivial apps benefit from both systems. Here are some patterns:</p><h3 id="classroom-lms-app" tabindex="-1">Classroom / LMS App <a class="header-anchor" href="#classroom-lms-app" aria-label="Permalink to “Classroom / LMS App”">​</a></h3><ul><li><strong>Database</strong> for courses, assignments, and grade records (admin-managed, cross-student queries)</li><li><strong>Documents</strong> for student submissions and collaborative group work (student-owned, real-time collaboration)</li></ul><h3 id="e-commerce-marketplace" tabindex="-1">E-Commerce / Marketplace <a class="header-anchor" href="#e-commerce-marketplace" aria-label="Permalink to “E-Commerce / Marketplace”">​</a></h3><ul><li><strong>Database</strong> for product catalog, orders, and inventory (server-enforced stock management, cross-user queries)</li><li><strong>Documents</strong> for shopping carts, wishlists, and saved preferences (user-owned, offline-capable)</li></ul><h3 id="team-workspace" tabindex="-1">Team Workspace <a class="header-anchor" href="#team-workspace" aria-label="Permalink to “Team Workspace”">​</a></h3><ul><li><strong>Database</strong> for organization settings, role definitions, and shared configuration (admin-controlled)</li><li><strong>Documents</strong> for project data, notes, and collaborative content (team-owned, real-time sync)</li></ul><h3 id="chat-messaging" tabindex="-1">Chat / Messaging <a class="header-anchor" href="#chat-messaging" aria-label="Permalink to “Chat / Messaging”">​</a></h3><ul><li><strong>Documents</strong> for message history within channels (real-time sync, per-channel sharing)</li><li><strong>Database</strong> for channel directory, user profiles, and cross-channel search indexes (cross-user queries)</li></ul><h3 id="multi-tenant-saas" tabindex="-1">Multi-Tenant SaaS <a class="header-anchor" href="#multi-tenant-saas" aria-label="Permalink to “Multi-Tenant SaaS”">​</a></h3><ul><li><strong>Database</strong> for tenant configuration, billing state, and feature flags (server-enforced invariants)</li><li><strong>Documents</strong> for per-tenant collaborative workspaces (tenant-scoped, real-time collaboration)</li></ul><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to “Design Principles”">​</a></h2><ol><li><p><strong>Start with the sharing model.</strong> If different users need different access to different data, those boundaries often map to documents. Shared reference data goes in a database.</p></li><li><p><strong>Don&#39;t fight the grain.</strong> If you need server-enforced validation or cross-user queries, use a database — don&#39;t try to build that on top of documents. If you need offline access and real-time collaboration, use documents — don&#39;t try to replicate that with a database.</p></li><li><p><strong>Use groups for access control.</strong> Both documents and databases integrate with Primitive&#39;s group system. Groups let you model teams, roles, and relationships without building custom permission logic.</p></li><li><p><strong>Keep documents focused.</strong> A document works best under ~10 MB. If data grows large, split across multiple documents by natural boundaries (per-project, per-channel, per-time-period).</p></li></ol><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to “Common Mistakes”">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Why It&#39;s a Problem</th><th>Better Approach</th></tr></thead><tbody><tr><td>Storing admin-managed content in documents</td><td>No server-side enforcement; any editor can change anything</td><td>Use a database with CEL access expressions</td></tr><tr><td>Building cross-user queries on documents</td><td>Documents are isolated per user/sharing group — no global queries</td><td>Use a database for data that needs cross-user visibility</td></tr><tr><td>Using databases for real-time collaborative editing</td><td>Databases don&#39;t have built-in conflict resolution or offline sync</td><td>Use documents for collaborative data</td></tr><tr><td>One giant document for everything</td><td>Performance degrades past ~10 MB; can&#39;t share subsets independently</td><td>Split into multiple documents by sharing context</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./working-with-documents.html">Working with Documents</a></strong> — Implement local-first collaborative data</li><li><strong><a href="./working-with-databases.html">Working with Databases</a></strong> — Implement server-side structured storage</li><li><strong><a href="./users-and-groups.html">Users and Groups</a></strong> — Set up access control for both systems</li></ul>',31)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
